  <div class="shell-card sticky top-3 z-20 flex flex-wrap items-center justify-between gap-4 px-4 py-3">
    <div>
      <p class="eyebrow">Resume Builder</p>
      <h2 class="text-xl font-extrabold text-[#17172b]">{{ template.name }}</h2>
    </div>

    <div class="flex flex-wrap gap-3">
      <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'overview' ? 'bg-[#5b5cf0] text-white' : 'bg-white text-[#17172b] border border-[#dfe3f6]'" (click)="activeTab = 'overview'">Overview</button>
      <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'content' ? 'bg-[#5b5cf0] text-white' : 'bg-white text-[#17172b] border border-[#dfe3f6]'" (click)="activeTab = 'content'">Content</button>
      <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'customize' ? 'bg-[#5b5cf0] text-white' : 'bg-white text-[#17172b] border border-[#dfe3f6]'" (click)="activeTab = 'customize'">Customize</button>
      <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'ai' ? 'bg-[#5b5cf0] text-white' : 'bg-white text-[#17172b] border border-[#dfe3f6]'" (click)="activeTab = 'ai'">AI Tools</button>
    </div>
  </div>

  <form class="grid gap-4 xl:grid-cols-[0.46fr_0.54fr]" [formGroup]="form" (ngSubmit)="submit()">
    <section class="grid gap-4 xl:max-h-[calc(100vh-7.5rem)] xl:grid-cols-[220px_1fr] xl:overflow-auto xl:pr-2">
      <aside class="shell-card h-fit p-4">
        <p class="eyebrow">Step Flow</p>
        <div class="mt-4 space-y-3">
          <button type="button" (click)="activeTab = 'overview'" class="w-full rounded-2xl px-4 py-3 text-left text-sm font-semibold transition"
                  [ngClass]="activeTab === 'overview' ? 'bg-[#5b5cf0] text-white' : 'bg-[#f8f9ff] text-[#475467]'">1. Template overview</button>
          <button type="button" (click)="activeTab = 'content'" class="w-full rounded-2xl px-4 py-3 text-left text-sm font-semibold transition"
                  [ngClass]="activeTab === 'content' ? 'bg-[#5b5cf0] text-white' : 'bg-[#f8f9ff] text-[#475467]'">2. Fill content</button>
          <button type="button" (click)="activeTab = 'customize'" class="w-full rounded-2xl px-4 py-3 text-left text-sm font-semibold transition"
                  [ngClass]="activeTab === 'customize' ? 'bg-[#5b5cf0] text-white' : 'bg-[#f8f9ff] text-[#475467]'">3. Customize style</button>
          <button type="button" (click)="activeTab = 'ai'" class="w-full rounded-2xl px-4 py-3 text-left text-sm font-semibold transition"
                  [ngClass]="activeTab === 'ai' ? 'bg-[#5b5cf0] text-white' : 'bg-[#f8f9ff] text-[#475467]'">4. AI tools</button>
        </div>
      </aside>

      <div class="space-y-4">
        <div *ngIf="activeTab === 'overview'" class="shell-card p-6">
          <p class="eyebrow">Template Overview</p>
          <h3 class="section-title mt-2 text-4xl text-[#17172b]">{{ template.name }}</h3>
          <p class="mt-4 text-base leading-7 text-[#667085]">
            Use this as a structured step-one screen: understand the template, confirm the category, then move into content entry and live preview.
          </p>
          <div class="mt-6 grid gap-4 md:grid-cols-2">
            <div class="soft-card p-5">
              <p class="text-sm text-[#667085]">Best for</p>
              <p class="mt-2 text-xl font-extrabold text-[#17172b]">{{ template.category }}</p>
            </div>
            <div class="soft-card p-5">
              <p class="text-sm text-[#667085]">Screening mode</p>
              <p class="mt-2 text-xl font-extrabold text-[#17172b]">{{ template.atsFriendly ? 'ATS-friendly' : 'Standard' }}</p>
            </div>
          </div>
        </div>

        <div *ngIf="activeTab === 'content'" class="space-y-4">
          <section class="shell-card p-6">
            <h3 class="text-2xl font-extrabold text-[#17172b]">Personal information</h3>
            <div class="mt-5 grid gap-4 md:grid-cols-2">
              <input class="field" formControlName="title" placeholder="Resume title">
              <input class="field" formControlName="fullName" placeholder="Full name">
              <input class="field" formControlName="headline" placeholder="Professional title / headline">
              <input class="field" formControlName="email" placeholder="Email">
              <input class="field" formControlName="phone" placeholder="Phone">
              <input class="field" formControlName="links" placeholder="GitHub / LinkedIn / Portfolio">
            </div>
          </section>

          <section class="shell-card p-6">
            <h3 class="text-2xl font-extrabold text-[#17172b]">Experience</h3>
            <div formArrayName="experience" class="mt-4 space-y-3">
              <div *ngFor="let group of experience.controls; let i = index" [formGroupName]="i" class="flex gap-3">
                <input class="field" formControlName="value" placeholder="Experience / internship bullet">
                <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(experience, i)">Remove</button>
              </div>
            </div>
            <button class="btn-secondary mt-3" type="button" (click)="addItem(experience)">Add Experience</button>
          </section>

          <section class="shell-card p-6">
            <h3 class="text-2xl font-extrabold text-[#17172b]">Projects</h3>
            <div formArrayName="projects" class="mt-4 space-y-3">
              <div *ngFor="let group of projects.controls; let i = index" [formGroupName]="i" class="flex gap-3">
                <input class="field" formControlName="value" placeholder="Project bullet">
                <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(projects, i)">Remove</button>
              </div>
            </div>
            <button class="btn-secondary mt-3" type="button" (click)="addItem(projects)">Add Project</button>
          </section>

          <section class="shell-card p-6">
            <div class="grid gap-6 lg:grid-cols-2">
              <div>
                <h3 class="text-2xl font-extrabold text-[#17172b]">Skills</h3>
                <div formArrayName="skills" class="mt-4 space-y-3">
                  <div *ngFor="let group of skills.controls; let i = index" [formGroupName]="i" class="flex gap-3">
                    <input class="field" formControlName="value" placeholder="Skill entry">
                    <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(skills, i)">Remove</button>
                  </div>
                </div>
                <button class="btn-secondary mt-3" type="button" (click)="addItem(skills)">Add Skill</button>
              </div>

              <div>
                <h3 class="text-2xl font-extrabold text-[#17172b]">Education</h3>
                <div formArrayName="education" class="mt-4 space-y-3">
                  <div *ngFor="let group of education.controls; let i = index" [formGroupName]="i" class="flex gap-3">
                    <input class="field" formControlName="value" placeholder="Education entry">
                    <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(education, i)">Remove</button>
                  </div>
                </div>
                <button class="btn-secondary mt-3" type="button" (click)="addItem(education)">Add Education</button>
              </div>
            </div>
          </section>

          <section class="shell-card p-6">
            <div class="grid gap-6 lg:grid-cols-3">
              <div>
                <h3 class="text-2xl font-extrabold text-[#17172b]">Certifications</h3>
                <div formArrayName="certifications" class="mt-4 space-y-3">
                  <div *ngFor="let group of certifications.controls; let i = index" [formGroupName]="i" class="flex gap-3">
                    <input class="field" formControlName="value" placeholder="Certification">
                    <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(certifications, i)">Remove</button>
                  </div>
                </div>
                <button class="btn-secondary mt-3" type="button" (click)="addItem(certifications)">Add Certification</button>
              </div>
              <div>
                <h3 class="text-2xl font-extrabold text-[#17172b]">Achievements</h3>
                <div formArrayName="achievements" class="mt-4 space-y-3">
                  <div *ngFor="let group of achievements.controls; let i = index" [formGroupName]="i" class="flex gap-3">
                    <input class="field" formControlName="value" placeholder="Achievement">
                    <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(achievements, i)">Remove</button>
                  </div>
                </div>
                <button class="btn-secondary mt-3" type="button" (click)="addItem(achievements)">Add Achievement</button>
              </div>
              <div>
                <h3 class="text-2xl font-extrabold text-[#17172b]">Languages</h3>
                <div formArrayName="languages" class="mt-4 space-y-3">
                  <div *ngFor="let group of languages.controls; let i = index" [formGroupName]="i" class="flex gap-3">
                    <input class="field" formControlName="value" placeholder="Language">
                    <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(languages, i)">Remove</button>
                  </div>
                </div>
                <button class="btn-secondary mt-3" type="button" (click)="addItem(languages)">Add Language</button>
              </div>
            </div>
          </section>
        </div>

        <div *ngIf="activeTab === 'customize'" class="space-y-4">
          <section class="shell-card p-6">
            <h3 class="text-2xl font-extrabold text-[#17172b]">Fonts</h3>
            <div class="mt-5 grid gap-3 md:grid-cols-2">
              <button *ngFor="let font of fontOptions" type="button" class="rounded-2xl border px-4 py-4 text-left font-semibold transition"
                      [ngClass]="form.value.designFont === font ? 'border-[#5b5cf0] bg-[#edf2ff] text-[#5b5cf0]' : 'border-[#dfe3f6] bg-white text-[#17172b]'"
                      (click)="form.patchValue({ designFont: font })">
                {{ font }}
              </button>
            </div>
          </section>

          <section class="shell-card p-6">
            <h3 class="text-2xl font-extrabold text-[#17172b]">Colors</h3>
            <div class="mt-5 flex flex-wrap gap-4">
              <button *ngFor="let color of accentOptions" type="button" class="h-14 w-14 rounded-full border-4 transition"
                      [style.background]="color"
                      [ngClass]="form.value.designAccent === color ? 'border-[#17172b] scale-110' : 'border-white'"
                      (click)="form.patchValue({ designAccent: color })"></button>
            </div>
          </section>

          <section class="shell-card p-6">
            <h3 class="text-2xl font-extrabold text-[#17172b]">Language & Region</h3>
            <div class="mt-5 grid gap-4 md:grid-cols-2">
              <select class="field" formControlName="pageFormat">
                <option value="A4">A4</option>
                <option value="Letter">Letter</option>
              </select>
              <input class="field" formControlName="designText" placeholder="Text color hex">
            </div>
          </section>
        </div>

        <div *ngIf="activeTab === 'ai'" class="shell-card p-6">
          <h3 class="text-2xl font-extrabold text-[#17172b]">AI Tools</h3>
          <p class="mt-4 text-base leading-7 text-[#667085]">
            This space is reserved for bullet rewrites, keyword optimization, and section-specific copy improvements once the premium workflow expands.
          </p>
        </div>

        <p *ngIf="error" class="rounded-2xl bg-[#fff1f1] px-4 py-3 text-sm font-medium text-[#ef4444]">{{ error }}</p>

        <div class="flex justify-end">
          <button class="btn-primary" type="submit" [disabled]="submitting">{{ submitting ? 'Generating...' : 'Create Resume' }}</button>
        </div>
      </div>
    </section>

    <section class="shell-card overflow-hidden p-3 xl:sticky xl:top-24">
      <div class="rounded-[2rem] bg-[#eef1ff] p-4">
        <iframe class="h-[calc(100vh-10rem)] min-h-[980px] w-full rounded-[1.5rem] border-0 bg-white shadow-2xl" [srcdoc]="previewHtml"></iframe>
      </div>
    </section>
  </form>
</div>
